f binary_search(arr: &[i32], target: i32) -> usize?
    @req arr.windows(2).all(|w| w[0] <= w[1]) "array must be sorted"
    @ens result.map_or(true, |i| arr[i] == target)
    @fx pure
{
    let mut lo = 0;
    let mut hi = arr.len();
    @w lo < hi {
        let mid = lo + (hi - lo) / 2;
        ?: arr[mid] == target { ret Some(mid) }
        ?: arr[mid] < target { lo = mid + 1 } _ { hi = mid }
    }
    None
}

