// Synthesized implementation (insertion sort)
f sort(arr: &mut [i32])
    @req arr.len() > 0
    @ens arr.windows(2).all(|w| w[0] <= w[1])
    @fx pure
{
    @ i in 1..arr.len() {
        let key = arr[i];
        let mut j = i;
        @w j > 0 && arr[j - 1] > key {
            arr[j] = arr[j - 1];
            j -= 1;
        }
        arr[j] = key;
    }
}

f reverse(arr: &mut [i32])
    @ens arr.len() == old(arr.len())
    @fx pure
{
    let n = arr.len();
    @ i in 0..n / 2 {
        arr.swap(i, n - 1 - i);
    }
}

f flatten<T: Clone>(nested: &[[T]~]) -> [T]~
    @ens result.len() == nested.iter().map(|v| v.len()).sum::<usize>()
    @fx pure
{
    let mut result = Vec.new();
    @ inner in nested {
        @ item in inner {
            result.push(item.clone());
        }
    }
    result
}

