// Safe MAGE wrapper
+f compress_safe(data: &[u8]) -> [u8]~!FfiError
    @req !data.is_empty() "input must not be empty"
    @fx unsafe
{
    let mut out = vec![0u8; data.len() * 2];
    let mut out_len: u64 = out.len() as u64;
    let rc = unsafe { compress(data.as_ptr(), data.len() as u64, out.as_mut_ptr(), &mut out_len) };
    ?: rc == 0 {
        out.truncate(out_len as usize);
        Ok(out)
    } _ {
        Err(FfiError.new(rc))
    }
}

